import{_ as e,c as d,o,a1 as a}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"История версий: Эволюция функций | opencode-agent-skills","description":"Изучите историю версий плагина OpenCode Agent Skills. Этот туториал содержит все основные обновления функций, исправления ошибок, улучшения архитектуры и описания критических изменений от v0.1.0 до v0.6.4.","frontmatter":{"title":"История версий: Эволюция функций | opencode-agent-skills","sidebarTitle":"Что нового в версии","subtitle":"История версий","description":"Изучите историю версий плагина OpenCode Agent Skills. Этот туториал содержит все основные обновления функций, исправления ошибок, улучшения архитектуры и описания критических изменений от v0.1.0 до v0.6.4.","tags":["Обновления версий","changelog","История релизов"],"order":3},"headers":[],"relativePath":"ru/joshuadavidthomas/opencode-agent-skills/changelog/index.md","filePath":"ru/joshuadavidthomas/opencode-agent-skills/changelog/index.md"}'),l={name:"ru/joshuadavidthomas/opencode-agent-skills/changelog/index.md"};function r(i,t,s,n,c,h){return o(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="история-версии" tabindex="-1">История версий <a class="header-anchor" href="#история-версии" aria-label="Permalink to &quot;История версий&quot;">​</a></h1><p>Этот документ содержит все обновления версий плагина OpenCode Agent Skills. Через историю версий вы можете узнать о пути эволюции функций, исправленных проблемах и улучшениях архитектуры.</p><div class="tip custom-block"><p class="custom-block-title">Текущая версия</p><p>Последняя стабильная версия — <strong>v0.6.4</strong> (2026-01-20)</p></div><h2 id="хронология-версии" tabindex="-1">Хронология версий <a class="header-anchor" href="#хронология-версии" aria-label="Permalink to &quot;Хронология версий&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Версия</th><th>Дата релиза</th><th>Тип</th><th>Основное содержание</th></tr></thead><tbody><tr><td>0.6.4</td><td>2026-01-20</td><td>Исправление</td><td>Парсинг YAML, поддержка Claude v2</td></tr><tr><td>0.6.3</td><td>2025-12-16</td><td>Улучшение</td><td>Оптимизация подсказок рекомендаций навыков</td></tr><tr><td>0.6.2</td><td>2025-12-15</td><td>Исправление</td><td>Разделение имени навыка и имени директории</td></tr><tr><td>0.6.1</td><td>2025-12-13</td><td>Улучшение</td><td>Избежание повторных рекомендаций загруженных навыков</td></tr><tr><td>0.6.0</td><td>2025-12-12</td><td>Новая функция</td><td>Семантическое сопоставление, предвычисление embedding</td></tr><tr><td>0.5.0</td><td>2025-12-11</td><td>Улучшение</td><td>Нечеткое сопоставление предложений, рефакторинг</td></tr><tr><td>0.4.1</td><td>2025-12-08</td><td>Улучшение</td><td>Упрощение способа установки</td></tr><tr><td>0.4.0</td><td>2025-12-05</td><td>Улучшение</td><td>Рекурсивный поиск скриптов</td></tr><tr><td>0.3.3</td><td>2025-12-02</td><td>Исправление</td><td>Обработка символических ссылок</td></tr><tr><td>0.3.2</td><td>2025-11-30</td><td>Исправление</td><td>Сохранение режима агента</td></tr><tr><td>0.3.1</td><td>2025-11-28</td><td>Исправление</td><td>Проблема переключения модели</td></tr><tr><td>0.3.0</td><td>2025-11-27</td><td>Новая функция</td><td>Функция списка файлов</td></tr><tr><td>0.2.0</td><td>2025-11-26</td><td>Новая функция</td><td>Режим Superpowers</td></tr><tr><td>0.1.0</td><td>2025-11-26</td><td>Начальная</td><td>4 инструмента, обнаружение в нескольких местах</td></tr></tbody></table><h2 id="подробныи-журнал-изменении" tabindex="-1">Подробный журнал изменений <a class="header-anchor" href="#подробныи-журнал-изменении" aria-label="Permalink to &quot;Подробный журнал изменений&quot;">​</a></h2><h3 id="v0-6-4-2026-01-20" tabindex="-1">v0.6.4 (2026-01-20) <a class="header-anchor" href="#v0-6-4-2026-01-20" aria-label="Permalink to &quot;v0.6.4 (2026-01-20)&quot;">​</a></h3><p><strong>Исправления</strong>:</p><ul><li>Исправлен парсинг YAML frontmatter для многострочных описаний навыков (поддержка блочных скаляров <code>|</code> и <code>&gt;</code>), путем замены пользовательского парсера на библиотеку <code>yaml</code></li><li>Добавлена поддержка формата плагина Claude v2, <code>installed_plugins.json</code> теперь использует массив установленных плагинов вместо отдельного объекта</li></ul><p><strong>Улучшения</strong>:</p><ul><li>Обнаружение кэша плагина Claude Code теперь поддерживает новую вложенную структуру директорий (<code>cache/&lt;marketplace&gt;/&lt;plugin&gt;/&lt;version&gt;/skills/</code>)</li></ul><h3 id="v0-6-3-2025-12-16" tabindex="-1">v0.6.3 (2025-12-16) <a class="header-anchor" href="#v0-6-3-2025-12-16" aria-label="Permalink to &quot;v0.6.3 (2025-12-16)&quot;">​</a></h3><p><strong>Улучшения</strong>:</p><ul><li>Оптимизированы подсказки оценки навыков, чтобы предотвратить отправку моделью сообщений типа &quot;навыки не нужны&quot; пользователю (пользователь не видит скрытые подсказки оценки)</li></ul><h3 id="v0-6-2-2025-12-15" tabindex="-1">v0.6.2 (2025-12-15) <a class="header-anchor" href="#v0-6-2-2025-12-15" aria-label="Permalink to &quot;v0.6.2 (2025-12-15)&quot;">​</a></h3><p><strong>Исправления</strong>:</p><ul><li>Валидация навыков теперь позволяет имени директории отличаться от <code>name</code> в frontmatter SKILL.md. <code>name</code> в frontmatter является стандартным идентификатором, имя директории используется только для организации. Это соответствует спецификации Anthropic Agent Skills.</li></ul><h3 id="v0-6-1-2025-12-13" tabindex="-1">v0.6.1 (2025-12-13) <a class="header-anchor" href="#v0-6-1-2025-12-13" aria-label="Permalink to &quot;v0.6.1 (2025-12-13)&quot;">​</a></h3><p><strong>Улучшения</strong>:</p><ul><li>Динамические рекомендации навыков теперь отслеживают уже загруженные навыки в каждой сессии, избегая повторных рекомендаций загруженных навыков, снижая избыточные подсказки и использование контекста</li></ul><h3 id="v0-6-0-2025-12-12" tabindex="-1">v0.6.0 (2025-12-12) <a class="header-anchor" href="#v0-6-0-2025-12-12" aria-label="Permalink to &quot;v0.6.0 (2025-12-12)&quot;">​</a></h3><p><strong>Добавлено</strong>:</p><ul><li><strong>Семантическое сопоставление навыков</strong>: после начальной инъекции списка навыков, последующие сообщения используют локальный embedding для сопоставления с описаниями навыков</li><li>Добавлена зависимость <code>@huggingface/transformers</code> для генерации локальных embedding (квантованная версия all-MiniLM-L6-v2)</li><li>При сопоставлении сообщений с доступными навыками внедряется 3-шаговая подсказка оценки (EVALUATE → DECIDE → ACTIVATE), поощряющая загрузку навыков (вдохновлено <a href="https://scottspence.com/posts/how-to-make-claude-code-skills-activate-reliably" target="_blank" rel="noreferrer">блог-постом</a> <a href="https://github.com/spences10" target="_blank" rel="noreferrer">@spences10</a>)</li><li>Дисковое кэширование embedding для низколатентного сопоставления (~/.cache/opencode-agent-skills/)</li><li>Очистка сессий при событии <code>session.deleted</code></li></ul><h3 id="v0-5-0-2025-12-11" tabindex="-1">v0.5.0 (2025-12-11) <a class="header-anchor" href="#v0-5-0-2025-12-11" aria-label="Permalink to &quot;v0.5.0 (2025-12-11)&quot;">​</a></h3><p><strong>Добавлено</strong>:</p><ul><li>Добавлены предложения нечеткого сопоставления &quot;Вы имели в виду...&quot; во все инструменты (<code>use_skill</code>, <code>read_skill_file</code>, <code>run_skill_script</code>, <code>get_available_skills</code>)</li></ul><p><strong>Улучшения</strong>:</p><ul><li><strong>Критическое изменение</strong>: инструмент <code>find_skills</code> переименован в <code>get_available_skills</code> для более четкого намерения</li><li><strong>Внутреннее</strong>: кодовая база реорганизована в независимые модули (<code>claude.ts</code>, <code>skills.ts</code>, <code>tools.ts</code>, <code>utils.ts</code>, <code>superpowers.ts</code>), повышена поддерживаемость</li><li><strong>Внутреннее</strong>: повышено качество кода путем удаления AI-генерированных комментариев и ненужного кода</li></ul><h3 id="v0-4-1-2025-12-08" tabindex="-1">v0.4.1 (2025-12-08) <a class="header-anchor" href="#v0-4-1-2025-12-08" aria-label="Permalink to &quot;v0.4.1 (2025-12-08)&quot;">​</a></h3><p><strong>Улучшения</strong>:</p><ul><li>Способ установки теперь использует npm-пакет через OpenCode config вместо git clone + символическая ссылка</li></ul><p><strong>Удалено</strong>:</p><ul><li>Удален <code>INSTALL.md</code> (больше не нужен после упрощения установки)</li></ul><h3 id="v0-4-0-2025-12-05" tabindex="-1">v0.4.0 (2025-12-05) <a class="header-anchor" href="#v0-4-0-2025-12-05" aria-label="Permalink to &quot;v0.4.0 (2025-12-05)&quot;">​</a></h3><p><strong>Улучшения</strong>:</p><ul><li>Обнаружение скриптов теперь выполняет рекурсивный поиск по всей директории навыков (максимальная глубина 10) вместо только корневой директории и поддиректории <code>scripts/</code></li><li>Скрипты теперь идентифицируются по относительным путям (например, <code>tools/build.sh</code>) вместо базовых имен</li><li>Параметр <code>skill_name</code> в инструментах <code>read_skill_file</code>, <code>run_skill_script</code> и <code>use_skill</code> переименован в <code>skill</code></li><li>Параметр <code>script_name</code> в инструменте <code>run_skill_script</code> переименован в <code>script</code></li></ul><h3 id="v0-3-3-2025-12-02" tabindex="-1">v0.3.3 (2025-12-02) <a class="header-anchor" href="#v0-3-3-2025-12-02" aria-label="Permalink to &quot;v0.3.3 (2025-12-02)&quot;">​</a></h3><p><strong>Исправления</strong>:</p><ul><li>Исправлено обнаружение файлов и директорий для корректной обработки символических ссылок с использованием <code>fs.stat</code></li></ul><h3 id="v0-3-2-2025-11-30" tabindex="-1">v0.3.2 (2025-11-30) <a class="header-anchor" href="#v0-3-2-2025-11-30" aria-label="Permalink to &quot;v0.3.2 (2025-11-30)&quot;">​</a></h3><p><strong>Исправления</strong>:</p><ul><li>Сохранение режима агента при внедрении синтетических сообщений в начале сессии</li></ul><h3 id="v0-3-1-2025-11-28" tabindex="-1">v0.3.1 (2025-11-28) <a class="header-anchor" href="#v0-3-1-2025-11-28" aria-label="Permalink to &quot;v0.3.1 (2025-11-28)&quot;">​</a></h3><p><strong>Исправления</strong>:</p><ul><li>Исправлено неожиданное переключение модели при использовании инструментов навыков путем явной передачи текущей модели в операции <code>noReply</code> (временное решение для проблемы opencode #4475)</li></ul><h3 id="v0-3-0-2025-11-27" tabindex="-1">v0.3.0 (2025-11-27) <a class="header-anchor" href="#v0-3-0-2025-11-27" aria-label="Permalink to &quot;v0.3.0 (2025-11-27)&quot;">​</a></h3><p><strong>Добавлено</strong>:</p><ul><li>Добавлен список файлов в вывод <code>use_skill</code></li></ul><h3 id="v0-2-0-2025-11-26" tabindex="-1">v0.2.0 (2025-11-26) <a class="header-anchor" href="#v0-2-0-2025-11-26" aria-label="Permalink to &quot;v0.2.0 (2025-11-26)&quot;">​</a></h3><p><strong>Добавлено</strong>:</p><ul><li>Добавлена поддержка режима Superpowers</li><li>Добавлено доказательство релиза</li></ul><h3 id="v0-1-0-2025-11-26" tabindex="-1">v0.1.0 (2025-11-26) <a class="header-anchor" href="#v0-1-0-2025-11-26" aria-label="Permalink to &quot;v0.1.0 (2025-11-26)&quot;">​</a></h3><p><strong>Добавлено</strong>:</p><ul><li>Добавлен инструмент <code>use_skill</code> для загрузки содержимого навыков в контекст</li><li>Добавлен инструмент <code>read_skill_file</code> для чтения вспомогательных файлов в директории навыков</li><li>Добавлен инструмент <code>run_skill_script</code> для выполнения скриптов из директории навыков</li><li>Добавлен инструмент <code>find_skills</code> для поиска и перечисления доступных навыков</li><li>Добавлено обнаружение навыков в нескольких местах (на уровне проекта, пользователя и совместимые с Claude места)</li><li>Добавлена валидация frontmatter в соответствии со спецификацией Anthropic Agent Skills Spec v1.0</li><li>Добавлена автоматическая инъекция списка навыков при начале сессии и после сжатия контекста</li></ul><p><strong>Новые участники</strong>:</p><ul><li>Josh Thomas <a href="mailto:josh@joshthomas.dev" target="_blank" rel="noreferrer">josh@joshthomas.dev</a> (мейнтейнер)</li></ul><h2 id="обзор-эволюции-функции" tabindex="-1">Обзор эволюции функций <a class="header-anchor" href="#обзор-эволюции-функции" aria-label="Permalink to &quot;Обзор эволюции функций&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Функция</th><th>Версия введения</th><th>Путь эволюции</th></tr></thead><tbody><tr><td>4 базовых инструмента</td><td>v0.1.0</td><td>v0.5.0 добавлено нечеткое сопоставление</td></tr><tr><td>Обнаружение навыков в нескольких местах</td><td>v0.1.0</td><td>v0.4.1 упрощена установка, v0.6.4 поддержка Claude v2</td></tr><tr><td>Автоматическая инъекция контекста</td><td>v0.1.0</td><td>v0.3.0 добавлен список файлов, v0.6.1 избежание повторных рекомендаций</td></tr><tr><td>Режим Superpowers</td><td>v0.2.0</td><td>Постоянно стабильный</td></tr><tr><td>Рекурсивный поиск скриптов</td><td>v0.4.0</td><td>v0.3.3 исправлены символические ссылки</td></tr><tr><td>Семантическое сопоставление рекомендаций</td><td>v0.6.0</td><td>v0.6.1 избежание повторов, v0.6.3 оптимизация подсказок</td></tr><tr><td>Нечеткое сопоставление предложений</td><td>v0.5.0</td><td>Постоянно стабильный</td></tr></tbody></table><h2 id="описание-критических-изменении" tabindex="-1">Описание критических изменений <a class="header-anchor" href="#описание-критических-изменении" aria-label="Permalink to &quot;Описание критических изменений&quot;">​</a></h2><h3 id="v0-6-0-функция-семантического-сопоставления" tabindex="-1">v0.6.0: Функция семантического сопоставления <a class="header-anchor" href="#v0-6-0-функция-семантического-сопоставления" aria-label="Permalink to &quot;v0.6.0: Функция семантического сопоставления&quot;">​</a></h3><p>Введена возможность семантического сопоставления на основе локальных embedding, позволяющая AI автоматически рекомендовать релевантные навыки на основе содержания сообщений пользователя, без необходимости запоминать имена навыков вручную.</p><ul><li><strong>Технические детали</strong>: используется модель <code>all-MiniLM-L6-v2</code> от HuggingFace (квантование q8)</li><li><strong>Механизм кэширования</strong>: результаты embedding кэшируются в <code>~/.cache/opencode-agent-skills/</code>, повышая скорость последующих сопоставлений</li><li><strong>Процесс сопоставления</strong>: сообщение пользователя → embedding → вычисление косинусного сходства с описаниями навыков → Топ 5 рекомендаций (порог 0.35)</li></ul><h3 id="v0-5-0-рефакторинг-и-переименование-инструментов" tabindex="-1">v0.5.0: Рефакторинг и переименование инструментов <a class="header-anchor" href="#v0-5-0-рефакторинг-и-переименование-инструментов" aria-label="Permalink to &quot;v0.5.0: Рефакторинг и переименование инструментов&quot;">​</a></h3><p>Архитектура кода реорганизована в модульный дизайн, имена инструментов стали более четкими:</p><ul><li><code>find_skills</code> → <code>get_available_skills</code></li><li><code>skill_name</code> → <code>skill</code></li><li><code>script_name</code> → <code>script</code></li></ul><h3 id="v0-4-0-улучшение-механизма-обнаружения-скриптов" tabindex="-1">v0.4.0: Улучшение механизма обнаружения скриптов <a class="header-anchor" href="#v0-4-0-улучшение-механизма-обнаружения-скриптов" aria-label="Permalink to &quot;v0.4.0: Улучшение механизма обнаружения скриптов&quot;">​</a></h3><p>Обнаружение скриптов обновлено с &quot;только корневая директория + scripts/&quot; до &quot;рекурсивный поиск по всей директории навыков&quot; (максимальная глубина 10), поддерживая более гибкие способы организации скриптов.</p><h3 id="v0-2-0-интеграция-superpowers" tabindex="-1">v0.2.0: Интеграция Superpowers <a class="header-anchor" href="#v0-2-0-интеграция-superpowers" aria-label="Permalink to &quot;v0.2.0: Интеграция Superpowers&quot;">​</a></h3><p>Добавлена поддержка режима рабочего процесса Superpowers, требуется установка навыка <code>using-superpowers</code> и установка переменной окружения <code>OPENCODE_AGENT_SKILLS_SUPERPOWERS_MODE=true</code>.</p><hr><h2 id="приложение-ссылки-на-исходныи-код" tabindex="-1">Приложение: Ссылки на исходный код <a class="header-anchor" href="#приложение-ссылки-на-исходныи-код" aria-label="Permalink to &quot;Приложение: Ссылки на исходный код&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы развернуть и посмотреть расположение исходного кода</strong></summary><blockquote><p>Время обновления: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Функция</th><th>Путь к файлу</th><th>Номер строки</th></tr></thead><tbody><tr><td>Текущий номер версии</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/package.json#L3-L3" target="_blank" rel="noreferrer"><code>package.json</code></a></td><td>3</td></tr><tr><td>История версий</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/CHANGELOG.md#L19-L152" target="_blank" rel="noreferrer"><code>CHANGELOG.md</code></a></td><td>19-152</td></tr></tbody></table><p><strong>Ключевая информация о версиях</strong>:</p><ul><li><code>v0.6.4</code>: Текущая версия (2026-01-20)</li><li><code>v0.6.0</code>: Введение семантического сопоставления (2025-12-12)</li><li><code>v0.5.0</code>: Версия рефакторинга (2025-12-11)</li><li><code>v0.1.0</code>: Начальная версия (2025-11-26)</li></ul></details>',72)])])}const v=e(l,[["render",r]]);export{p as __pageData,v as default};
